LAYER
	NAME "sector"
	TYPE polygon
	STATUS on
	DATA "geom FROM (SELECT gid, id_ubigeo, cod_sector, area_grafi, peri_grafi, geom FROM geo.tg_sector) as kaypacha using unique gid using srid=32719"
	INCLUDE "configuracion/postgresql_kaypacha.map"
	CLASSITEM "gid"
	PROJECTION
	"init=epsg:32719"
	END
	METADATA
		"layer_encoding" "Latin1"
		"wfs_encoding" "Latin1"
		"queryable" "true"
		"wfs_abstract" "Sector || Municipalidad Distrital de Wanchaq - Cusco :: Perú"
		"wfs_title" "Sector"
		"wfs_credit" "Kaypacha"
		"wfs_srs" "EPSG:32719"
		"gml_include_items" "all"
		"gml_featureid" "gid"
		"wfs_getfeature_formatlist" "OGRGML,SHAPE-ZIP,CSV,geojson"
		#"wfs_additional_files_in_output" "lotes.pdf,lotes.lyr"
	END
	CLASS
		NAME "Sectores"
		STYLE
			COLOR -1 -1 -1
			OUTLINECOLOR 100 107 99
			WIDTH 1
		END
	END
END # Layer